SELECT
t.*,
t1.real_name create_user_name
FROM
member_wx t
LEFT OUTER JOIN castle_sys_user t1 ON t.create_user  = t1.id
WHERE
t.is_deleted = 2

    AND t.id = #{memberWxEntity.id}


    AND t.member_id = #{memberWxEntity.memberId}


    AND t.nick_name like concat('%',#{memberWxEntity.nickName},'%')


    AND t.sex = #{memberWxEntity.sex}


    AND t.province like concat('%',#{memberWxEntity.province},'%')


    AND t.city like concat('%',#{memberWxEntity.city},'%')


    AND t.country like concat('%',#{memberWxEntity.country},'%')


    AND t.head_img_url like concat('%',#{memberWxEntity.headImgUrl},'%')


    AND t.status = #{memberWxEntity.status}


    AND t.create_user like concat('%',#{memberWxEntity.createUser},'%')


    AND t.create_time = #{memberWxEntity.createTime}


    AND t.update_user like concat('%',#{memberWxEntity.updateUser},'%')


    AND t.update_time like concat('%',#{memberWxEntity.updateTime},'%')


    AND t.is_deleted = #{memberWxEntity.isDeleted}


    AND t.open_id = #{memberWxEntity.openId}


    AND t.union_id = #{memberWxEntity.unionId}

    order by create_time desc

    limit #{map.offset},#{map.rows}

SELECT
    count(1)
FROM
member_wx t
WHERE
    t.is_deleted = 2

    AND t.id = #{memberWxEntity.id}


    AND t.member_id = #{memberWxEntity.memberId}


    AND t.nick_name like concat('%',#{memberWxEntity.nickName},'%')


    AND t.sex = #{memberWxEntity.sex}


    AND t.province like concat('%',#{memberWxEntity.province},'%')


    AND t.city like concat('%',#{memberWxEntity.city},'%')


    AND t.country like concat('%',#{memberWxEntity.country},'%')


    AND t.head_img_url like concat('%',#{memberWxEntity.headImgUrl},'%')


    AND t.status = #{memberWxEntity.status}


    AND t.create_user like concat('%',#{memberWxEntity.createUser},'%')


    AND t.create_time = #{memberWxEntity.createTime}


    AND t.update_user like concat('%',#{memberWxEntity.updateUser},'%')


    AND t.update_time like concat('%',#{memberWxEntity.updateTime},'%')


    AND t.is_deleted = #{memberWxEntity.isDeleted}


    AND t.open_id = #{memberWxEntity.openId}


    AND t.union_id = #{memberWxEntity.unionId}
